function setCookie(name, value, days) {
    var expires = "";
    if (days) {
        var date = new Date();
        date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
        expires = "; expires=" + date.toUTCString();
    }
    document.cookie = name + "=" + (value || "") + expires + "; path=/";
}

function getCookie(name) {
    var nameEQ = name + "=";
    var ca = document.cookie.split(';');
    for (var i = 0; i < ca.length; i++) {
        var c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1, c.length);
        if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
}

function autoLogin() {
    var userData = getCookie('userData');
    if (userData) {
        var data = JSON.parse(atob(userData));
        // Assuming a function login(username, passwordHash) exists
        login(data.username, data.passwordHash);
    }
}

function login(username, password) {
    // Your existing login logic here
    // On successful login:
    var passwordHash = hashPassword(password); // Assume hashPassword is defined
    if (document.getElementById('rememberMe').checked) {
        var userData = btoa(JSON.stringify({ username: username, passwordHash: passwordHash }));
        setCookie('userData', userData, 30);
    }
}

// Call autoLogin on page load
window.onload = autoLogin;